/**
 * @fileoverview DynamicSearch helpers — pure utility functions.
 * @module module/DynamicSearch/helpers
 */

import razyui from '../../index.js';

/** Shared div for HTML-escaping text (created once). */
const _escDiv = typeof document !== 'undefined' ? razyui.el('div') : null;

/**
 * Escape a string for safe insertion as HTML text content.
 *
 * @param {string} str — raw text
 * @returns {string} HTML-safe string
 */
export function escapeHTML(str) {
    if (!_escDiv) return str;
    return _escDiv.text(str).html();
}

/**
 * Highlight occurrences of `keyword` in `text` with `<mark>` tags.
 * Text is HTML-escaped first to prevent injection.
 *
 * @param {string} text    — raw text to highlight within
 * @param {string} keyword — search keyword
 * @param {string} [cls]   — optional CSS class for the <mark> element
 * @returns {string} HTML string with highlighted matches
 */
export function highlightMatch(text, keyword, cls) {
    if (!keyword) return escapeHTML(text);
    const escaped = keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const re = new RegExp('(' + escaped + ')', 'gi');
    const tag = cls ? `<mark class="${cls}">` : '<mark>';
    return escapeHTML(text).replace(re, tag + '$1</mark>');
}

/**
 * Extract the value from a result item using the config extractor.
 *
 * @param {object} item   — result data object
 * @param {object} config — component config with `value` key/function
 * @returns {string}
 */
export function extractValue(item, config) {
    if (typeof config.value === 'function') return config.value(item);
    if (typeof config.value === 'string') return item[config.value] ?? '';
    return item.id ?? item.value ?? '';
}

/**
 * Extract the label from a result item using the config extractor.
 *
 * @param {object} item   — result data object
 * @param {object} config — component config with `label` key/function
 * @returns {string}
 */
export function extractLabel(item, config) {
    if (typeof config.label === 'function') return config.label(item);
    if (typeof config.label === 'string') return item[config.label] ?? '';
    return item.name ?? item.label ?? item.text ?? '';
}
