/**
 * @fileoverview DynamicSearch state — reactive state creation.
 * @module module/DynamicSearch/state
 */

/**
 * Create the reactive state set for a DynamicSearch instance.
 *
 * @param {Function} stateFn — `razyui.state` factory
 * @param {HTMLInputElement} el — original input element (used for initial values)
 * @returns {Array} stateSet — [stateRef, setState] with `.effect()` method
 */
export function createReactiveState(stateFn, el) {
    return stateFn({
        value: el.value || '',
        selectedItem: null,
        disabled: el.disabled,
        readonly: el.hasAttribute('readonly'),
        open: false,
        loading: false,
        locked: false,     // true when an item is selected
    });
}
